function active$VoucherFilter$(f) {
  f.add_onResponseComplete(on$Filter$ResponseComplete);
  changeLookupReadonly(f, 'ma_dvcs');&FilterExpression;
  onchange$ReportPeriod(f.getItem('ky_bc'));
}
/* <flatten type="Javascript"> */
function close$VoucherFilter$(f) {try {f.remove_onResponseComplete(on$Filter$ResponseComplete);} catch (ex) {}}
function on$Filter$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result, g = f.grid;
  switch (context) {
    case 'Checking':
      var dFrom = f.getItem('tu_ngay').value, x = f.getItemValue('mau_bc'), y = f.getItemValue('kieu_bc'), z = f.getItemValue('ky_bc'), v = g._language == 'v';
      var _report = (v ? 'Báo cáo theo: ' : 'Report by:'), _period = (v ? 'số kỳ báo cáo: ' : 'No. of Periods:');
      switch (y) {
        case '1':
          _report = _report + " " + (v ? 'Tháng' : 'Month');
          break;
        case '2':
          _report = _report + " " + (v ? 'Quý' : 'Quarter');
          break;
        case '3':
          _report = _report + " " + (v ? 'Nửa năm' : 'Half a Year');
          break;
        case '4':
          _report = _report + " " + (v ? 'Năm' : 'Year');
          break;
        default:
          break;
      }
      g._alterTitle = [null, [['%t', _report, true], ['%p', _period + " " + z, true], ['%d2', dFrom, true]]];
      g._queryFilterString = getQueryFilterString(f, 'tu_ngay, kieu_bc, sKy_bc, bc_theo, nhom_theo, phan_loai, ma_dvcs, mau_bc, loai_du_lieu, ds_ma_ct, tk_dt');

      var c = z + String.fromCharCode(255) + f.getItemValue('mau_bc');
      if (!g._v) g._v = c;
      if (g._v != c) {
        remove$GridReport$Filter(g);
        g._v = c;
      }
      break;
    default:
      break;
  }
}
function onchange$ReportPeriod(o) {
  var f = o.parentForm, k = f.getItem('ky_bc').value;
  f.setItemValue('sKy_bc', k);
}
